// Type surface for `@symphony/automation`. The runtime is JavaScript; these
// types exist so the user's coding harness can type-check the script it
// authors. The Rust-side spec generator regenerates inline copies from this
// file so the inbox spec can never drift from the runtime.

export type Schedule =
  | { cron: string }
  | { every: "1h" | "6h" | "1d" };

export interface Ctx {
  /** ISO-stable watermark of the previous successful run start. `null` on first run. */
  lastRunAt: Date | null;
  /** True when invoked through the Dry-run button — side effects are no-ops. */
  dryRun: boolean;
  /** Append a line to the run log captured by the daemon. */
  log: (msg: string) => void;
}

export interface AutomationDef {
  name: string;
  schedule: Schedule;
  run: (ctx: Ctx) => Promise<void>;
}

export function defineAutomation(def: AutomationDef): AutomationDef;

export interface IssueFilter {
  assignee?: "@me" | string;
  state?: "open" | "closed" | "any";
  labels?: string[];
  /** `owner/name`. Omit for all tracked repos. */
  repos?: string[];
  /** Pass `ctx.lastRunAt` to keep reruns incremental. */
  updatedSince?: Date | null;
}

export interface IssueRow {
  title: string;
  url: string;
  repo: string;
  number: number;
  labels: string[];
  author: string;
  updatedAt: Date;
}

export type PrFilter = IssueFilter;
export type PrRow = IssueRow;

export interface InboxCreate {
  title: string;
  url?: string;
  tags?: string[];
  body?: string;
  /** Required. Same dedupKey for this automation = no-op. Typically the source URL. */
  dedupKey: string;
}

export interface TabsOpen {
  url: string;
  title?: string;
  dedupKey: string;
}

export const symphony: {
  github: {
    issues(filter: IssueFilter): Promise<IssueRow[]>;
    prs(filter: PrFilter): Promise<PrRow[]>;
  };
  inbox: {
    create(entry: InboxCreate): Promise<void>;
  };
  tabs: {
    open(tab: TabsOpen): Promise<void>;
  };
};
